import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options

def capture_screenshot(url):
    CHROMEDRIVER_PATH = '/path/to/chromedriver' # replace with the path to chromedriver

    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--window-size=1024x768")
    
    browser = webdriver.Chrome(executable_path=CHROMEDRIVER_PATH, options=chrome_options)
    browser.get(url)
    screenshot = browser.save_screenshot("screenshot.png")
    browser.quit()

def upload_to_s3(file_name, bucket, object_name=None):
    s3_client = boto3.client('s3')
    if object_name is None:
        object_name = file_name
    response = s3_client.upload_file(file_name, bucket, object_name)
    return response

url = 'http://www.example.com'  # replace with the url to be screenshot
capture_screenshot(url)
upload_to_s3("screenshot.png", "your-aws-s3-bucket-name")